+std::shared_ptr<EndLiftSession::Active> EndLiftSession::Active::make(
+  agv::RobotContextPtr context,
+  std::string lift_name,
+  std::string destination)
+{
+  auto inst = std::shared_ptr<Active>(
+        new Active(
+          std::move(context),
+          std::move(lift_name),
+          std::move(destination)));
+  inst->_init_obs();
+  return inst;
+}
